mapper.select:
/*
	 SQL ID : ReviewDAO.countReviewInfo
	 설  명 : 복습기간 현황 > 복습기간 정보 목록 수
*/
SELECT COUNT(1)
  FROM TB_LMS_CRS TLC
 INNER JOIN TB_LMS_SBJCT TLCC
	ON TLC.CRS_ID = TLCC.CRS_ID 
 INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR
	ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID
   AND TLC.DELYN = 'N'
   AND TLCC.DELYN = 'N'
   AND TLC.ORG_ID = #{orgId}

	AND TLCC.SBJCT_ID = #{crsCreCd}
	AND TLCC.SBJCT_ID = #{creYear}
	AND TLCC.CRS_ID = #{creTerm}
	AND TLTCCR.CRS_SMSTR_ID = #{termCd}
	AND TLCC.DEPT_CD = #{deptCd}
	AND TLCC.USEYN = #{useYn}
	AND TLCC.ATNDLC_CERT_STSCD = #{enrlCertStatus}
	AND TLCC.UNIV_CD = #{uniCd}

		AND TLC.SBJCT_TYCD IN

			#{item}



		AND (
			   LOWER(TLCC.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
			OR LOWER(TLCC.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
		)

/*
	 SQL ID : ReviewDAO.reviewListPaging
	 설  명 : 복습기간 현황 > 복습기간 정보 목록 페이징
*/



	AND TLCC.SBJCT_ID = #{crsCreCd}
	AND TLCC.SBJCT_ID = #{creYear}
	AND TLCC.CRS_ID = #{creTerm}
	AND TLTCCR.CRS_SMSTR_ID = #{termCd}
	AND TLCC.DEPT_CD = #{deptCd}
	AND TLCC.ATNDLC_CERT_STSCD = #{enrlCertStatus}
	AND TLCC.UNIV_CD = #{uniCd}

		AND TLC.SBJCT_TYCD IN

			#{item}



		AND (
			   LOWER(TLCC.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
			OR LOWER(TLCC.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))
		)


	ORDER BY TLCC.SBJCT_ID

/* SQL ID : ReviewDAO.reviewListExcel 설 명 : 복습기간 현황 > 복습기간 정보 엑셀 리스트 */ SELECT ROW_NUMBER() OVER(ORDER BY TLCC.SBJCT_ID DESC) AS LINE_NO , TLCC.SBJCT_OP_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = TLC.ORG_ID AND CTGRCD = 'LEARNING_TYPE' AND CD = TLCC.SBJCT_OP_TYCD) AS CRS_OPER_TYPE_NM , TLCC.DEPT_CD , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = TLC.ORG_ID AND DEPT_CD = TLCC.DEPT_CD AND USEYN = 'Y') AS DEPTNM , TLC.CRS_ID , TLCC.SBJCT_ID , TLCC.SBJCTNM , TLCC.DVCLAS_NO , (CASE WHEN IFNULL(TLCC.RVW_STSCD,'0') = 0 THEN '불가' WHEN IFNULL(TLCC.RVW_STSCD,'0') = 1 THEN '영구' WHEN IFNULL(TLCC.RVW_STSCD,'0') = 2 THEN CONCAT('기간설정', ' (', DATE_FORMAT(TLCC.RVW_SDTTM, '%Y.%m.%d'), ' ~ ', DATE_FORMAT(TLCC.RVW_EDTTM, '%Y.%m.%d'), ')') ELSE '' END) AS RVW_STSCD FROM TB_LMS_CRS TLC INNER JOIN TB_LMS_SBJCT TLCC ON TLC.CRS_ID = TLCC.CRS_ID INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN TLTCCR ON TLCC.SBJCT_ID = TLTCCR.SBJCT_ID AND TLC.DELYN = 'N' AND TLCC.DELYN = 'N' AND TLC.ORG_ID = #{orgId}
AND TLCC.SBJCT_ID = #{crsCreCd} AND TLCC.SBJCT_ID = #{creYear} AND TLCC.CRS_ID = #{creTerm} AND TLTCCR.CRS_SMSTR_ID = #{termCd} AND TLCC.DEPT_CD = #{deptCd} AND TLCC.ATNDLC_CERT_STSCD = #{enrlCertStatus} AND TLCC.UNIV_CD = #{uniCd}
AND TLC.SBJCT_TYCD IN
#{item}
AND ( LOWER(TLCC.CRS_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(TLCC.SBJCTNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
ORDER BY TLCC.SBJCT_ID

mapper.update:
/*
	 SQL ID : ReviewDAO.updateReview
	 설  명 : 복습기간설정
*/
UPDATE TB_LMS_SBJCT
   SET RVW_STSCD = #{reviewStatus}

		, RVW_SDTTM = DATE_FORMAT(#{reviewStartDttm},'%Y%m%d')


		, RVW_EDTTM = DATE_FORMAT(#{reviewEndDttm},'%Y%m%d')

	   , MDFR_ID = #{mdfrId}
	   , MOD_DTTM = FN_DTTM()
 WHERE SBJCT_ID = #{crsCreCd}

/*
	 SQL ID : ReviewDAO.updateReview
	 설  명 : 복습기간설정
*/
UPDATE TB_LMS_SBJCT
   SET RVW_STSCD = #{reviewStatus}

	   , RVW_SDTTM = DATE_FORMAT(#{startDtString},'%Y%m%d')


	   , RVW_EDTTM = DATE_FORMAT(#{endDtString},'%Y%m%d')

	   , MDFR_ID = #{mdfrId}
	   , MOD_DTTM = FN_DTTM()
 WHERE SBJCT_ID = #{crsCreCd}
